WITH top_routes AS (SELECT concat(trimRight(toString(Origin)), '-', trimRight(toString(Dest))) AS route FROM default.ontime WHERE Year BETWEEN 2019 AND 2021 GROUP BY route ORDER BY count() DESC, route LIMIT 50) SELECT concat(trimRight(toString(o.Origin)), '-', trimRight(toString(o.Dest))) AS route, multiIf(o.Month IN (12, 1, 2), 'Winter', o.Month IN (3, 4, 5), 'Spring', o.Month IN (6, 7, 8), 'Summer', 'Fall') AS season, avg(o.DepDelay) AS avg_dep_delay, count() AS flights FROM default.ontime AS o INNER JOIN top_routes AS t ON concat(trimRight(toString(o.Origin)), '-', trimRight(toString(o.Dest))) = t.route WHERE o.Year BETWEEN 2019 AND 2021 GROUP BY route, season ORDER BY avg_dep_delay DESC, flights DESC, route, season LIMIT 1
